INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07180', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Lewin在場域理論（Field theory）中介紹了一些概念以協助瞭解在團體中運作的力量，其內容不包括：', '["同理心", "一致性", "支配力", "凝聚力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07181', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社工員對案主社區系統預估架構的內容，可以不包括：', '["社區權力關係", "社區界線及人口統計特性", "社區主要的價值觀念", "社區服務輸送體系"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07182', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在助人過程中的結案和評估階段，其主要工作不包括：', '["評估結案的準備", "消除改變的障礙", "彼此擬訂結案計畫", "擬訂維持改變和成長計畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07183', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者選擇適當理論與處置方法的標準，何者錯誤？', '["抽象層次較高的理論，其解釋範圍較廣，適合做為處置的理論", "所採取的理論是否經過實證經驗的驗證", "兩種處置方法都被證實有效時，其中較不費時、經濟與省力的方法優先", "社會工作者應選擇與自己知識及技術水準一致的處置方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07184', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區有許多種分類的方法，Twelvetrees（1990）將社區分為「功能性」與「地理性」；Cox 等人（1977） 則依社區是否組織化，將社區分為「已組織」與「未組織」的社區。若以上述二種分類，請問「中華民 國智障者家長總會」屬於何種社區類型？', '["未組織的地理型社區", "未組織的功能型社區", "已組織的地理型社區", "已組織的功能型社區"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07185', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '與家庭會談是社會工作者重要工作之一，當需要進入家庭所屬的社區中或是進行家訪時，他們可能會遭 遇各種類型的危險。下列何者不是協助社會工作者保護自身安全的合適作法？', '["家訪前應將行程（如：家訪的地點、日期、預計訪談的時間等）事先告知同事或是督導", "中國人重視待客之道。當家訪時，案家準備的點心或飲料，應該要禮貌性的食用，以免辜負案家的心意", "若不確定案家或其所處社區的安全性，可與家庭約在公共場所進行會談", "若案家成員中有傳染性的疾病，社會工作者應針對暴露在此疾病中的風險進行評估，確定安全無虞再 進行會談"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07186', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在一個身心障礙者家長情緒支持團體中，團體領導者說到：「王太太，我想起上次團體中，妳提到當醫 師和妳說：『孩子為中度自閉症』時，妳擔心得一個月都失眠。剛才，張太太分享了和妳一樣的經歷， 對於她的感受，妳的感覺是什麼？」，上述領導者使用的是何種團體技巧？', '["對他人的回應", "自我揭露", "重新建構與再界定", "連結成員間的溝通"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07187', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '針對服務對象優勢的評估，是社會工作重要的工作焦點，下列何者不是社會工作者應該進行優勢評估的 原因？', '["透過優勢的評估，可以提高服務對象的自尊與自我價值感，使其相信自己有能量面對現有及未來的問題", "社會工作者若只重視服務對象的限制、忽視優勢，則容易不自覺的阻礙服務對象成長的潛力", "優勢觀點是社會工作較新的處遇理論，社會工作者應該運用新的觀點來協助服務對象，才符合專業倫理", "進行優勢評估時，必須同時注意服務對象「個人」與「環境」層面的優勢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07188', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「重新提出老問題或提出新問題」是案主面對結案時的分離焦慮，可能出現的反應。下列對於這個反應 的敘述，何者錯誤？', '["若經過審慎的觀察、評估與討論之後，社會工作者與案主可以思考重新擬定契約以增加會談次數，將 結案時間延後", "在結案階段，若平時話不多的案主，突然變得多話或做過深的自我坦露，則可能是案主不想面對結案 的反應", "若案主在結案階段提出新問題，社會工作者應該立即轉移會談的焦點，優先處理案主所提出的新問題", "不論是重新提出老問題或是提出新問題，都可以協助案主與社會工作者重新思考結案的適切性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07189', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「保密」是社會工作者重要的倫理原則，下列關於保密的敘述，何者錯誤？', '["督導為了監督服務的品質或是提升社會工作者個案服務的專業知能，社會工作者在知會案主同意的前 提下，是可以閱讀個案紀錄的", "有時其他單位因為轉介或工作的需要，向社會工作者要求提供案主相關資料時，社會工作者可以透過 很多方式來處理保密的要求，像是：取得案主願意提供資料的同意書、提供案主必要的訊息，而非所 有資料都提供等", "當案主涉及虐待兒童、老人或其他家人時，社會工作者可以放棄保密的倫理原則", "不論在任何情況下，社會工作者的個案紀錄不能讓機構以外的人（如：評鑑委員、外聘督導等）閱讀， 以免損及對案主資料的保密"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
